package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.criteria.Criterium;
import be.schaubroeck.lpb.tools.service.util.StandaardLoService;
import be.schaubroeck.lpb.tools.service.util.TemporalUtil;
import be.schaubroeck.lpb.tools.util.InitializeAdmin;
import be.schaubroeck.util.persistence.Identifiable;
import org.joda.time.LocalDateTime;

import java.util.HashSet;
import java.util.Set;
import java.util.stream.Collectors;

public abstract class StandaardLOCachedService<T extends Identifiable> {

    public abstract StandaardLoService<T> standaardLoService();

    public Set<T> findByIds(Admin admin, Set<Integer> ids) {
        return findByIds(admin, ids, "");
    }

    public Set<T> findByObjectIds(Admin admin, Set<T> objects) {
        return findByObjectIds(admin, objects, "");
    }

    @InitializeAdmin
    public Set<T> findByIds(Admin admin, Set<Integer> ids, String fetchString) {
        CriteriaBuilder cb = new CriteriaBuilder();
        cb.fetch(fetchString);
        cb.and("id", Criterium.IN(ids));
        return new HashSet<>(standaardLoService().findByCriteria(admin, cb));
    }

    @InitializeAdmin
    public Set<T> findByObjectIds(Admin admin, Set<T> objects, String fetchString) {
        Set<Integer> ids = objects.stream()
                .map(Identifiable::getId)
                .collect(Collectors.toSet());

        CriteriaBuilder cb = new CriteriaBuilder();
        cb.fetch(fetchString);
        cb.and("id", Criterium.IN(ids));
        return new HashSet<>(standaardLoService().findByCriteria(admin, cb));
    }

    public Set<T> findByIdstByRecordTimeAndActualFree(Admin admin, Set<Integer> ids, LocalDateTime tijdstip, String fetchString) {
        return TemporalUtil.getRecordTimeAndActualFree(tijdstip, () -> findByIds(admin, ids, fetchString));
    }

    public Set<T> findByObjectIdsByRecordTimeAndActualFree(Admin admin, Set<T> objects, LocalDateTime tijdstip, String fetchString) {
        return TemporalUtil.getRecordTimeAndActualFree(tijdstip, () -> findByObjectIds(admin, objects, fetchString));
    }
}
